package de.drremote.dsp408controller.core.protocol; import java.util.HashMap; import java.util.Locale; import java.util.Map; public enum DspChannel { IN_A(0, "InA"), IN_B(1, "InB"), IN_C(2, "InC"), IN_D(3, "InD"), OUT_1(4, "Out1"), OUT_2(5, "Out2"), OUT_3(6, "Out3"), OUT_4(7, "Out4"), OUT_5(8, "Out5"), OUT_6(9, "Out6"), OUT_7(10, "Out7"), OUT_8(11, "Out8"); private final int index; private final String displayName; private static final Map<String, DspChannel> ALIASES = buildAliases(); DspChannel(int index, String displayName) { this.index = index; this.displayName = displayName; } public int index() { return index; } public String displayName() { return displayName; } public static DspChannel parse(String value) { String normalized = normalize(value); DspChannel channel = ALIASES.get(normalized); if (channel == null) { throw new IllegalArgumentException("Unknown channel: " + value); } return channel; } private static String normalize(String value) { return value.trim().toLowerCase(Locale.ROOT) .replace("_", "") .replace("-", ""); } private static Map<String, DspChannel> buildAliases() { Map<String, DspChannel> map = new HashMap<>(); map.put("0", IN_A); map.put("ina", IN_A); map.put("inputa", IN_A); map.put("a", IN_A); map.put("1", IN_B); map.put("inb", IN_B); map.put("inputb", IN_B); map.put("b", IN_B); map.put("2", IN_C); map.put("inc", IN_C); map.put("inputc", IN_C); map.put("c", IN_C); map.put("3", IN_D); map.put("ind", IN_D); map.put("inputd", IN_D); map.put("d", IN_D); map.put("4", OUT_1); map.put("out1", OUT_1); map.put("output1", OUT_1); map.put("5", OUT_2); map.put("out2", OUT_2); map.put("output2", OUT_2); map.put("6", OUT_3); map.put("out3", OUT_3); map.put("output3", OUT_3); map.put("7", OUT_4); map.put("out4", OUT_4); map.put("output4", OUT_4); map.put("8", OUT_5); map.put("out5", OUT_5); map.put("output5", OUT_5); map.put("9", OUT_6); map.put("out6", OUT_6); map.put("output6", OUT_6); map.put("10", OUT_7); map.put("out7", OUT_7); map.put("output7", OUT_7); map.put("11", OUT_8); map.put("out8", OUT_8); map.put("output8", OUT_8); return Map.copyOf(map); } }